import{_ as o,o as t,c as i,ah as r}from"./chunks/framework.Bi9enVNS.js";const m=JSON.parse('{"title":"Errors and Limits","description":"","frontmatter":{},"headers":[],"relativePath":"en/reference/errors-and-limits.md","filePath":"en/reference/errors-and-limits.md","lastUpdated":1774205896000}'),d={name:"en/reference/errors-and-limits.md"};function a(l,e,s,c,n,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="errors-and-limits" tabindex="-1">Errors and Limits <a class="header-anchor" href="#errors-and-limits" aria-label="Permalink to &quot;Errors and Limits&quot;">​</a></h1><p>This page collects protocol errors, HTTP status codes, and current implementation limits in one place.</p><h2 id="batch-level-failures" tabindex="-1">Batch-level failures <a class="header-anchor" href="#batch-level-failures" aria-label="Permalink to &quot;Batch-level failures&quot;">​</a></h2><p>The whole batch is rejected when:</p><ul><li><code>request_id</code> is missing</li><li><code>project</code> is missing</li><li><code>environment</code> is missing</li><li><code>producer</code> is missing</li><li><code>producer.protocol_version != &quot;v1&quot;</code></li><li><code>records</code> is empty</li><li><code>records</code> exceeds the configured limit</li><li>body decoding fails</li><li><code>Content-Type</code> is unsupported</li><li><code>Content-Encoding</code> is unsupported</li></ul><h2 id="record-level-failures" tabindex="-1">Record-level failures <a class="header-anchor" href="#record-level-failures" aria-label="Permalink to &quot;Record-level failures&quot;">​</a></h2><p>A single record is rejected into <code>errors[]</code> when:</p><ul><li><code>event_time</code> is missing</li><li><code>severity_number</code> falls outside <code>0..24</code></li><li>the effective source is invalid</li><li><code>trace_id</code> has an invalid format</li><li><code>span_id</code> has an invalid format</li><li><code>trace_flags</code> has an invalid format</li></ul><h2 id="http-status-codes" tabindex="-1">HTTP status codes <a class="header-anchor" href="#http-status-codes" aria-label="Permalink to &quot;HTTP status codes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>200</code></td><td>Upload succeeded, or partially succeeded</td></tr><tr><td><code>400</code></td><td>Invalid request, decode failure, or malformed query parameters</td></tr><tr><td><code>401</code></td><td>Missing bearer token, or token not authorized for the project</td></tr><tr><td><code>413</code></td><td>Request body exceeds the configured limit</td></tr><tr><td><code>500</code></td><td>Internal normalization or storage failure</td></tr></tbody></table><h2 id="current-limits" tabindex="-1">Current limits <a class="header-anchor" href="#current-limits" aria-label="Permalink to &quot;Current limits&quot;">​</a></h2><ul><li>Default maximum of <code>1000</code> log records per request</li><li>Default maximum decompressed body size of <code>1 MiB</code></li><li>In-memory storage only</li><li>Process-local idempotency cache</li><li>Fixed idempotency TTL of 24 hours</li><li>No pagination in query endpoints</li><li>Query result ordering is fixed in code</li></ul><h2 id="what-it-does-not-do-today" tabindex="-1">What it does not do today <a class="header-anchor" href="#what-it-does-not-do-today" aria-label="Permalink to &quot;What it does not do today&quot;">​</a></h2><ul><li>It does not build graphs from span parent-child relationships</li><li>It does not expose <code>observed_time</code> in query responses</li><li>It does not search attributes or resource through <code>keyword</code></li></ul><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>docs/protocol.md</code></li><li><code>internal/api/http.go</code></li><li><code>internal/ingest/decode.go</code></li><li><code>internal/ingest/service.go</code></li><li><code>internal/ingest/validate.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',16)])])}const p=o(d,[["render",a]]);export{m as __pageData,p as default};
